class Solution:
    def decodeMessage(self, key, message):
        table = {' ': ' '}
        plain = 'abcdefghijklmnopqrstuvwxyz'
        i = 0
        for ch in key:
            if ch != ' ' and ch not in table:
                table[ch] = plain[i]
                i += 1
        out = ''
        for ch in message:
            out += table[ch]
        return out

