class Solution:
    def decodeMessage(self, key, message):
        table = {}
        nxt = ord('a')
        for ch in key:
            if ch != ' ' and ch not in table:
                table[ch] = chr(nxt)
                nxt += 1
        return ''.join(table.get(c, ' ') for c in message)

