var decodeMessage = function(key, message) {
    const table = {};
    let nxt = 'a'.charCodeAt(0);
    for (const ch of key) {
        if (ch !== ' ' && !(ch in table)) {
            table[ch] = String.fromCharCode(nxt);
            nxt++;
        }
    }
    let out = '';
    for (const ch of message) {
        out += ch === ' ' ? ' ' : table[ch];
    }
    return out;
};
